import requests

def fetch_event_results(event_id):
    api_url = f"https://api.wrestlingdata.com/events/{event_id}/results"
    response = requests.get(api_url)
    if response.status_code == 200:
        return response.json()
    else:
        return None

# Example usage
results = fetch_event_results("forbidden-door-london-2025")
if results:
    retained_champs = [match for match in results if "retain" in match.get("result", "").lower()]
    for champ in retained_champs:
        print(f"{champ['champion']} retained the {champ['title']}.")
